var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"정말 이런 곳에 통로가 숨겨져 있었군요.","JPN":"本当にこんなところに通路が隠されていたのですね。","ENG":"So there really was a pathway hidden here.","TWN":"這種地方竟然真的藏有通道，"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"확실히 주인님께서는…… 비밀이 많은 분이셨죠.","JPN":"確かにご主人様は……秘密の多い方ではありますが。","ENG":"Master always was a... man with a lot of secrets.","TWN":"主人確實……有很多不為人知的秘密呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"신분 확인 완료. 환영합니다, 베로니카 씨.","JPN":"身元確認完了。こんにちは、ベロニカさん。","ENG":"Identity confirmed. Welcome, Miss Veronica.","TWN":"身分確認完畢，你好，貝洛妮卡。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이 회사에서 신세를 지는 동안 못 뵀던 분인데…… 누구시죠?","JPN":"この会社にお世話になって以来、一度もお目にかかったことのない方ですが……どちら様でしょうか。","ENG":"I don't recall seeing you while I was here... And you are...?","TWN":"我之前在公司裡似乎沒見過你……請問你是哪位？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"관리국 오퍼레이팅 시스템 모네카예요.","JPN":"管理局のオペレーティングシステムのモネカです。","ENG":"I am Moneka, the Administration's operating system.","TWN":"我是管理局的領航系統 莫奈卡。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"어떤 분야에서든 최고의 성능을 발휘하는 첨단 인공지능이죠.","JPN":"どんな分野においても最高の性能を発揮する最先端の人工知能なんです。","ENG":"I am a highly developed artificial intelligence that excels in every field.","TWN":"是在任何領域中，皆能夠發揮最強性能的頂尖人工智慧。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇군요. 주인님 주위에 제가 모르는 분이 계신 줄 알고 놀랐습니다.","JPN":"そうですか。ご主人様の周りにまだ知らない方がいたのかと驚きました。","ENG":"I see. I was surprised to see someone I didn't recognize around Master.","TWN":"原來是這樣，沒想到主人身邊有我不認識的人，有點驚訝呢。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께서는 제가 여기 온 걸 알고 계신가요?","JPN":"ご主人様は私がここに来たことをご存じなのでしょうか？","ENG":"Does Master know that I'm here?","TWN":"主人知道我來這裡嗎？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"확인해 드리고는 싶지만, 관리자님과는 현재 연락이 끊긴 상태입니다.","JPN":"確認してさしあげたいのですが、管理者様とはただいま連絡が取れない状態です。","ENG":"I wish I could be of help, but the Administrator has currently turned off his comms.","TWN":"我也想為你確認，但現在無法聯絡上管理者。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그 대신 저에게 베로니카 씨가 오시면 이 말을 꼭 전해 주라고 하셨어요.","JPN":"その代わり、ベロニカさんが来られたら必ず伝えるようにと言われた言葉を預かっています。","ENG":"However, he did tell me to deliver this message to you when you come here.","TWN":"不過管理者有吩咐我，貝洛妮卡來的話要將這段話轉告你。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>희생은 이제 지긋지긋하다</color>고요.","JPN":"<color=#ffd34c>犠牲はもうこりごりだ</color>と。","ENG":"He said, <color=#ffd34c>\\"I'm tired of sacrifices.\\"</color>","TWN":"<color=#ffd34c>我已經對犧牲感到厭煩</color>。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이 밑에는 최고 관리자 권한으로 통제되고 있는 중요 시설이 존재합니다.","JPN":"この下には最高管理者の権限で統制されている重要施設が存在します。","ENG":"Below exists an important facility controlled only by the Supreme Administrator authorization.","TWN":"這底下有最高管理者權限在控管的重要設施。"},"stage":{"bg":"LIFT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"직접적인 출입 허가가 없는 이상, 저희는 시설의 보안을 우선시할 수밖에 없어요.","JPN":"直接的な出入り許可がない以上、私たちは施設の保安を優先するしかありません。","ENG":"Unless you have direct access, we have to prioritize the security of this facility.","TWN":"若沒有出入許可，我們只能以設施的安全為第一優先考量。"},"stage":{"bg":"LIFT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"베로니카 씨는 관리자님과 친밀한 사이시죠? 더 늦기 전에 이만 지상으로 돌아가세요.","JPN":"ベロニカさんは管理者様と親しい間柄ですよね？　まだ間に合います。地上へお戻りください。","ENG":"Miss Veronica, you are close with the Administrator, right? I suggest you head back up before it is too late.","TWN":"貝洛妮卡和管理者是熟識吧？那就請儘快回到上面吧。"},"stage":{"bg":"LIFT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저 역시, 여러 분들께 심려를 끼치게 된 점은 송구스럽게 여기고 있습니다.","JPN":"私も皆さんにご心配をおかけしたことは申し訳なく思っております。","ENG":"I feel sorry for causing concern for everyone.","TWN":"造成各位的困擾，我也很過意不去。"},"stage":{"bg":"LIFT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 제가 들은 이야기가 사실이라면……","JPN":"ですが、私が聞いた話が本当なら……","ENG":"However, if what I heard is true...","TWN":"但若我聽到的是事實……"},"stage":{"bg":"LIFT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님을 위해, 주인님의 말씀을 외면할 수밖에 없어요.","JPN":"ご主人様のために、ご主人様のお言葉を無視するしかないのです。","ENG":"I have no choice but to ignore Master's words, for his sake.","TWN":"那為了主人，我只能選擇不理會主人的話。"},"stage":{"bg":"LIFT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};